module RefModule (
    input clk,
    input reset,
    input t,
    output q );reg q_reg;
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (reset)
            q_reg <= 1'b0;
        else if (t)
            q_reg <= ~q_reg;
    end

    assign q = q_reg;

endmodule
